var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"아이구, 이게 누구신가? 세계를 구한 영웅, 우리 딸이잖아?","JPN":"おやおや、誰かと思えば、世界を救った英雄、我が娘じゃないか？","ENG":"Well, look who it is! It's the hero who saved the world, my daughter!","TWN":"哎呀，瞧瞧這是誰？這不是我的女兒，拯救世界的英雄嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하, 하하……. 오랜만에 찾아 뵙네요. 아빠.","JPN":"ハ、ハハ……お久しぶりです。お父さん。","ENG":"Ha, ha ha... It's been a while, Dad.","TWN":"哈，哈哈……爸爸好久不見。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"피, 피난 지구 쪽 쉘터는 어떠세요……?","JPN":"ひ、避難地区のシェルターはどう？","ENG":"H-how's the refugee district...?","TWN":"庇，庇護中心那邊的生活怎麼樣……？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭐 불편한 건 없어요? 음식은 잘 배급되는 거 맞죠? 카린 양이 특별히 신경 써준다고는 했는데…….","JPN":"何か不便なところは？　食料はちゃんと配給されてる？　カリンさんが気を遣ってくれるって言っていたけど……","ENG":"Anything you need? Are you getting enough provisions? Karin told me she'd take special care of you...","TWN":"有沒有哪裡不方便的？有按時候拿到食物吧？卡琳說過會特別關照的……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"하하. 걱정하지 말라구, 딸?","JPN":"はは、大丈夫だ。","ENG":"Ha ha. Don't you worry.","TWN":"哈哈，不用擔心，女兒。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"말도 없이, 생환 가능성 5%의 미친 작전에 덜컥 지원하더니…….","JPN":"相談もなしに、生還確率5％のイカレた作戦に突然志願して……","ENG":"You sneakily apply for a crazy operation with a 5% survival chance...","TWN":"你沒說一聲就報名參加生還率只有5%的作戰……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"죽었는지 살았는지 연락도 없다가, 이제서야 난데없이 나타난 딸 덕분에 잘 먹고 잘 살고 있으니까.","JPN":"生死がわからないまま連絡もずっとなし、と思っていたらいきなり現れた娘のおかげでちゃんと贅沢に暮らせているぞ。","ENG":"Leave us in the dark, making us wonder if you're even alive or dead, and suddenly reappear. But sure, the refugee district is fine.","TWN":"然後就沒消沒息，是死是活都不知道，現在才突跑出來現……放心，我們過得很好。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아이 참. 또 비꼬기 시작이시네. 이렇게 살아 돌아왔으니까, 됐잖아요~","JPN":"もう、また嫌味が始まった。こうして生きて帰ってきたんだからいいじゃない～","ENG":"Oh, c'mon. Again with the passive aggression. I'm back alive. Isn't that what matters?","TWN":"討厭，你又在挖苦我，反正我平安回來就好啦～"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"애초에 엄마 아빠가 반대할 걸 아니까 말하지 않았던 거라고요.","JPN":"そもそもお母さんやお父さんは反対するってわかっていたから、言わなかったの。","ENG":"I didn't tell you because I knew you and Mom would never agree to it.","TWN":"我知道你們一定會反對，所以才沒說的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그러고보니, 엄마는요?","JPN":"そういえば、お母さんは？","ENG":"Speaking of, where is Mom?","TWN":"不過，怎麼沒看到媽媽？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"하하, 나랑 달리 엄마가 속이 좀 좁잖아?","JPN":"はは、お父さんと違って、お母さんは心が狭いだろ？","ENG":"Ha ha, unlike me, she's a bit stubborn.","TWN":"哈哈，你媽和我不一樣，她很小心眼。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"네가 그 작전에 참여하겠다고 나간 뒤로 다시는 얼굴 안 보겠다고 고집을 부리더구나.","JPN":"お前がその作戦に参加するって言って出て行って以来、二度と顔を合わせたくないと意地を張っているんだ。","ENG":"She was adamant about not seeing you after you participated in that operation.","TWN":"知道你參加那個作戰後，她就很生氣，說要和你斷絕母女關係。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"알잖아? 네가 용병일 하는 것도 싫어하던 사람이야.","JPN":"わかっているだろう？　お母さんはお前が傭兵の仕事をするのも嫌がっていたんだ。","ENG":"You know how she was also against you being a mercenary.","TWN":"你也知道，她一直很不喜歡你當傭兵。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에효, 우리 엄마도 참 여전하네.","JPN":"はぁ、お母さんは相変わらずなのね。","ENG":"Geez, she hasn't changed a bit, has she?","TWN":"哀，我媽還是老樣子呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"요즘 같은 세상에 용병이 얼마나 프로페셔널한 대접을 받는데요.","JPN":"最近の世の中では、傭兵はプロフェッショナルの待遇を受けるっていうのに。","ENG":"She should know how well mercenaries are treated these days.","TWN":"現在這個世道，傭兵的待遇不知道多好呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그리고 저 정도면 군의 의뢰도 접수 받는 최고급 용병이라구요, 엣헴!","JPN":"それに、私は軍からの依頼もくるほど、最高ランクの傭兵なんだから、えっへん！","ENG":"And I'm one of the top mercenaries that accepts contracts from the military, too!","TWN":"而且，我這種可是能夠接受部隊委託的最高級傭兵呢，嘿嘿！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"그래, 우리 딸이 세상을 구할 정도로 좀 대단하긴 하지.","JPN":"そうだな、お前は世界を救えるくらいすごいんだもんな。","ENG":"Yeah, I guess you ARE the savior of the world.","TWN":"沒錯，我們女兒確實厲害，還能拯救世界呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};